function o(r,e={}){if(!r)return"—";const t=new Date(r);return new Intl.DateTimeFormat("en-US",{year:"numeric",month:"short",day:"numeric",...e}).format(t)}function a(r){if(!r)return"—";const e=new Date(r),n=Math.floor((new Date-e)/1e3);return n<60?"Just now":n<3600?`${Math.floor(n/60)} min ago`:n<86400?`${Math.floor(n/3600)} hours ago`:n<604800?`${Math.floor(n/86400)} days ago`:o(r)}function f(r){return r==null?"—":new Intl.NumberFormat("en-US").format(r)}function u(r,e="USD"){return r==null?"—":new Intl.NumberFormat("en-US",{style:"currency",currency:e}).format(r)}export{o as a,a as b,u as c,f};
